import React, { useState } from 'react';
import { Link } from 'react-router-dom';
import axios from 'axios';
import { FaHeart, FaRegHeart, FaEye } from 'react-icons/fa';
import moment from 'moment';
import toast from 'react-hot-toast';

export default function VideoCard({ video }) {
    const [isLiked, setIsLiked] = useState(video.is_liked || false);
    const [likesCount, setLikesCount] = useState(video.like_count || 0);
    const token = localStorage.getItem('access_token');

    const handleLike = async (e) => {
        e.preventDefault();
        e.stopPropagation();

        if (!token) {
            toast.error('Войдите чтобы поставить лайк');
            setTimeout(() => {
                window.location.href = '/login';
            }, 1500);
            return;
        }

        try {
            const response = await axios.post(`/videos/${video.id}/like/`);
            setIsLiked(response.data.status === 'liked');
            setLikesCount(response.data.count);
        } catch (error) {
            console.error('Error liking video:', error);
            toast.error('Ошибка');
        }
    };

    return (
        <Link to={`/video/${video.id}`} className="block group">
            <div className="bg-gray-900 rounded-xl overflow-hidden transition-all duration-300 hover:scale-105 hover:shadow-2xl">
                <div className="relative pb-[56.25%]">
                    {video.thumbnail ? (
                        <img
                            src={video.thumbnail}
                            alt={video.title}
                            className="absolute inset-0 w-full h-full object-cover group-hover:scale-110 transition duration-300"
                        />
                    ) : (
                        <div className="absolute inset-0 bg-gradient-to-br from-purple-900 to-pink-900 flex items-center justify-center">
                            <span className="text-5xl group-hover:scale-110 transition">🎬</span>
                        </div>
                    )}
                    <div className="absolute bottom-2 right-2 bg-black bg-opacity-75 px-1.5 py-0.5 rounded text-xs text-white">
                        {video.duration ? `${Math.floor(video.duration / 60)}:${String(video.duration % 60).padStart(2, '0')}` : '0:00'}
                    </div>
                </div>
                <div className="p-3">
                    <h3 className="font-semibold text-white line-clamp-2 text-sm group-hover:text-purple-400 transition">
                        {video.title}
                    </h3>
                    <p className="text-sm text-gray-400 mt-1 hover:text-purple-400 transition">
                        {video.author?.username}
                    </p>
                    <div className="flex items-center justify-between mt-2">
                        <div className="flex items-center space-x-3 text-xs text-gray-500">
                            <span className="flex items-center space-x-1">
                                <FaEye className="text-xs" />
                                <span>{video.views?.toLocaleString()}</span>
                            </span>
                            <span>{moment(video.created_at).fromNow()}</span>
                        </div>
                        <button
                            onClick={handleLike}
                            className={`flex items-center space-x-1 text-xs px-2 py-1 rounded-full transition ${
                                isLiked 
                                    ? 'bg-red-600/20 text-red-500' 
                                    : 'bg-gray-800 text-gray-500 hover:bg-gray-700'
                            }`}
                        >
                            {isLiked ? <FaHeart className="text-xs" /> : <FaRegHeart className="text-xs" />}
                            <span>{likesCount}</span>
                        </button>
                    </div>
                </div>
            </div>
        </Link>
    );
}
